class Solution {
public:
int numSubseq(vector<int>& A, int target) {
    int n = A.size();
    sort(A.begin(), A.end());
    int m = -1;
    for (int i = n - 1; i >= 0; i--) {
        if (A[i] <= target) {
            m++;
            A.push_back(A[i]);
        }
    }
    return m;
}


